function evidenceList(ids){
  return ids.map((id)=>{
    const e=evidenceById.get(id); if(!e) throw new Error(`Unknown evidence ${id}`);
    return `<li class="rounded-2xl border border-slate-200 bg-white p-5" data-evidence-id="${esc(id)}"><a class="font-bold text-brand-blue underline" href="${esc(e.url)}" rel="noopener noreferrer" target="_blank">${esc(e.manufacturer)} — ${esc(e.title)}</a><span class="mt-2 block text-sm text-slate-600">Применимость: ${esc((e.modelScope||[]).join(', '))}</span></li>`;
  }).join('');
}

function faqSchema(page,title,faq){
  return `<script type="application/ld+json" data-generated="faq-registry">${JSON.stringify({
    '@context':'https://schema.org','@type':'FAQPage','@id':`https://mospochin.ru/${page}#faq`,url:`https://mospochin.ru/${page}`,name:title,
    mainEntity:faq.map(([q,a])=>({'@type':'Question',name:q,acceptedAnswer:{'@type':'Answer',text:a}}))
  },null,2)}</script>`;
}

function head(page, entry, spec){
  const type=spec.kind==='article'?'Article':'Service';
  const primary = type==='Article' ? {
    '@context':'https://schema.org','@type':'Article','@id':`https://mospochin.ru/${page}#article`,url:`https://mospochin.ru/${page}`,headline:spec.hero,description:spec.description,inLanguage:'ru-RU',author:{'@id':'https://mospochin.ru/#organization'},publisher:{'@id':'https://mospochin.ru/#organization'}
  } : {
    '@context':'https://schema.org','@type':'Service','@id':`https://mospochin.ru/${page}#service`,url:`https://mospochin.ru/${page}`,name:spec.hero,description:spec.description,serviceType:spec.hero,provider:{'@type':'LocalBusiness','@id':'https://mospochin.ru/#organization'},areaServed:'Москва и Московская область',inLanguage:'ru-RU'
  };
  const crumb={
    '@context':'https://schema.org','@type':'BreadcrumbList',itemListElement:[
      {'@type':'ListItem',position:1,name:'Главная',item:'https://mospochin.ru/'},
      {'@type':'ListItem',position:2,name:'Промышленные посудомоечные машины',item:'https://mospochin.ru/posudomoechnye-mashiny.html'},
      ...(page==='posudomoechnye-mashiny.html'?[]:[{'@type':'ListItem',position:3,name:spec.hero,item:`https://mospochin.ru/${page}`}])
    ]
  };
  return `<!DOCTYPE html><html lang="ru" class="scroll-smooth"><head><link rel="preload" href="/assets/fonts/manrope-700.woff2" as="font" type="font/woff2" crossorigin><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><link rel="icon" href="favicon.svg" type="image/svg+xml"><link rel="preload" href="/assets/fonts/manrope.css" as="style"><link rel="stylesheet" href="/assets/fonts/manrope.css"><link rel="preload" href="/assets/fonts/remixicon.css" as="style"><link rel="stylesheet" href="/assets/fonts/remixicon.css"><link rel="preload" href="styles-combined.css" as="style"><link rel="stylesheet" href="styles-combined.css"><script src="main.js" defer></script><script src="telegram-form.js" defer></script><script src="analytics.js" defer></script><title>${esc(entry.title)} | MosPochin</title><meta name="description" content="${esc(spec.description)}"><meta property="og:title" content="${esc(entry.title)} | MosPochin"><meta property="og:description" content="${esc(spec.description)}"><meta property="og:image" content="https://mospochin.ru/og-image.svg"><meta property="og:url" content="https://mospochin.ru/${page}"><meta property="og:type" content="website"><meta property="og:locale" content="ru_RU"><meta name="twitter:card" content="summary_large_image"><link rel="canonical" href="https://mospochin.ru/${page}"><script type="application/ld+json">${JSON.stringify(primary,null,2)}</script><script type="application/ld+json">${JSON.stringify(crumb,null,2)}</script>${faqSchema(page,entry.title,spec.faq)}</head>`;
}

function cards(items){return `<div class="mt-8 grid gap-5 md:grid-cols-2 lg:grid-cols-4">${items.map(([icon,t,d])=>`<article class="rounded-2xl border border-slate-200 bg-white p-6 shadow-sm"><i class="${icon} text-3xl text-brand-orange"></i><h3 class="mt-4 text-lg font-extrabold text-brand-blue">${esc(t)}</h3><p class="mt-2 leading-relaxed text-slate-600">${esc(d)}</p></article>`).join('')}</div>`}
function list(items){return items.map((x,i)=>`<li class="rounded-2xl border border-slate-200 bg-white p-5"><span class="text-sm font-extrabold text-brand-orange">${String(i+1).padStart(2,'0')}</span><p class="mt-2 leading-relaxed text-slate-700">${esc(x)}</p></li>`).join('')}
function matrix(rows){return `<div class="mt-8 overflow-x-auto rounded-2xl border border-slate-200"><table class="min-w-full bg-white text-left"><thead class="bg-slate-100"><tr><th class="px-4 py-4">Контур или узел</th><th class="px-4 py-4">Проявление</th><th class="px-4 py-4">Что проверяется</th></tr></thead><tbody>${rows.map(r=>`<tr class="border-t border-slate-200"><td class="px-4 py-4 font-bold text-brand-blue">${esc(r[0])}</td><td class="px-4 py-4 text-slate-600">${esc(r[1])}</td><td class="px-4 py-4 text-slate-600">${esc(r[2])}</td></tr>`).join('')}</tbody></table></div>`}
function related(page,slug){return `<section class="bg-slate-50 py-16"><div class="mx-auto max-w-6xl px-4 sm:px-6 lg:px-8"><p class="text-sm font-extrabold uppercase tracking-[0.2em] text-brand-orange">Связанные страницы</p><h2 class="mt-3 text-3xl font-display font-extrabold text-brand-blue">Перейти к нужному этапу или симптому</h2><div class="mt-8 grid gap-4 md:grid-cols-2 lg:grid-cols-3">${commonLinks.filter(x=>x[0]!==page).map(([href,t,d],i)=>`<a class="rounded-2xl border border-slate-200 bg-white p-5 transition hover:-translate-y-0.5 hover:border-brand-orange hover:shadow-md" href="${href}" data-block="related_links" data-cta-group="internal_link" data-cta-id="${slug}_related_${i+1}"><span class="block font-bold text-brand-blue">${esc(t)}</span><span class="mt-1 block text-sm text-slate-500">${esc(d)}</span></a>`).join('')}</div></div></section>`}
function form(page,spec,slug){return `<section class="bg-brand-blue py-16" id="request"><div class="mx-auto grid max-w-6xl gap-8 px-4 sm:px-6 lg:grid-cols-[0.85fr_1.15fr] lg:px-8"><div class="text-white"><p class="text-sm font-extrabold uppercase tracking-[0.2em] text-brand-orange">Заявка на диагностику</p><h2 class="mt-3 text-3xl font-display font-extrabold">Передайте модель и этап сбоя</h2><p class="mt-4 leading-relaxed text-white/75">Чем точнее указаны модель, код и момент остановки цикла, тем быстрее можно подготовить диагностический сценарий.</p><a href="tel:+79990057172" class="mt-6 inline-flex items-center gap-2 font-extrabold text-white" data-block="request" data-cta-group="phone" data-cta-id="${slug}_request_phone"><i class="ri-phone-line"></i>8 (999) 005-71-72</a></div><form class="telegram-form rounded-3xl border border-slate-200 bg-white p-6 shadow-xl lg:p-8" data-block="lead_form" data-contact-form="primary" data-cta-group="lead_form" data-cta-id="${slug}_form_01"><input name="problem" type="hidden" value="${esc(spec.hero)}"><input name="cluster" type="hidden" value="dishwasher"><div class="grid gap-5 md:grid-cols-2"><div><label class="mb-2 block text-sm font-bold text-slate-700">Ваше имя</label><input autocomplete="name" class="w-full rounded-xl border-2 border-slate-200 px-4 py-3" name="name" type="text"></div><div><label class="mb-2 block text-sm font-bold text-slate-700">Телефон *</label><input autocomplete="tel" class="w-full rounded-xl border-2 border-slate-200 px-4 py-3" inputmode="tel" name="phone" required type="tel"></div><div><label class="mb-2 block text-sm font-bold text-slate-700">Производитель и модель</label><input class="w-full rounded-xl border-2 border-slate-200 px-4 py-3" name="equipment_model" placeholder="Winterhalter PT, Abat МПК-700К..." type="text"></div><div><label class="mb-2 block text-sm font-bold text-slate-700">Код или сообщение</label><input class="w-full rounded-xl border-2 border-slate-200 px-4 py-3" name="error_code" placeholder="Если отображается" type="text"></div><div><label class="mb-2 block text-sm font-bold text-slate-700">Этап цикла</label><select class="w-full rounded-xl border-2 border-slate-200 px-4 py-3" name="wash_stage"><option value="">Выберите этап</option><option value="filling">Наполнение</option><option value="heating">Нагрев</option><option value="washing">Мойка</option><option value="rinsing">Ополаскивание</option><option value="draining">Слив</option></select></div><div><label class="mb-2 block text-sm font-bold text-slate-700">Серийный номер</label><input class="w-full rounded-xl border-2 border-slate-200 px-4 py-3" name="serial_number" type="text"></div><div class="md:col-span-2"><label class="mb-2 block text-sm font-bold text-slate-700">Что происходит</label><textarea class="w-full rounded-xl border-2 border-slate-200 px-4 py-3" name="details" placeholder="Опишите этап, звук, уровень воды и повторяемость" rows="4"></textarea></div></div><button class="mt-5 w-full rounded-xl bg-green-600 px-6 py-4 text-lg font-extrabold text-white" type="submit"><i class="ri-send-plane-line mr-2"></i>Отправить заявку</button></form></div></section>`}
function faqSection(faq){return `<section class="bg-white py-16"><div class="mx-auto max-w-4xl px-4 sm:px-6 lg:px-8"><p class="text-center text-sm font-extrabold uppercase tracking-[0.2em] text-brand-orange">FAQ</p><h2 class="mt-3 text-center text-3xl font-display font-extrabold text-brand-blue">Частые вопросы</h2><div class="mt-8 grid gap-4">${faq.map(([q,a])=>`<details class="rounded-2xl border border-slate-200 bg-white p-5"><summary class="cursor-pointer font-bold text-brand-blue">${esc(q)}</summary><p class="mt-3 leading-relaxed text-slate-600">${esc(a)}</p></details>`).join('')}</div></div></section>`}

function main(page,entry,spec){
 const slug=slugOf(page);
 const isHub=page==='posudomoechnye-mashiny.html';
 return `<main><nav class="border-b border-slate-100 bg-white"><div class="mx-auto max-w-6xl px-4 py-4 text-sm text-slate-500 sm:px-6 lg:px-8"><a class="hover:text-brand-blue" href="${isHub?'uslugi.html':'posudomoechnye-mashiny.html'}" data-block="breadcrumb" data-cta-group="internal_link" data-cta-id="${slug}_breadcrumb_parent">${isHub?'Ресторанное оборудование':'Промышленные посудомоечные машины'}</a>${isHub?'':'<span class="mx-2">/</span><span>'+esc(spec.hero)+'</span>'}</div></nav><section class="bg-gradient-to-br from-brand-blue via-slate-900 to-slate-800 py-20 text-white lg:py-28"><div class="mx-auto max-w-6xl px-4 sm:px-6 lg:px-8"><p class="text-sm font-extrabold uppercase tracking-[0.2em] text-brand-orange">${esc(spec.eyebrow)}</p><h1 class="mt-4 max-w-5xl text-4xl font-display font-extrabold leading-tight sm:text-5xl lg:text-6xl">${esc(spec.hero)}</h1><p class="mt-6 max-w-3xl text-lg leading-relaxed text-white/80 sm:text-xl">${esc(spec.lead)}</p><div class="mt-8 flex flex-wrap gap-3"><a class="rounded-xl bg-brand-orange px-6 py-4 font-extrabold text-white" href="#diagnostics" data-block="hero" data-cta-group="diagnostic" data-cta-id="${slug}_hero_diagnostics">Разобрать симптом</a><a class="rounded-xl border border-white/30 px-6 py-4 font-extrabold text-white" href="#request" data-block="hero" data-cta-group="lead_form" data-cta-id="${slug}_hero_request">Передать модель инженеру</a></div></div></section><section class="bg-white py-16 lg:py-24"><div class="mx-auto max-w-6xl px-4 sm:px-6 lg:px-8"><p class="text-sm font-extrabold uppercase tracking-[0.2em] text-brand-orange">Технический контекст</p><h2 class="mt-3 text-3xl font-display font-extrabold text-brand-blue">${esc(spec.introTitle)}</h2><div class="mt-6 max-w-4xl space-y-4 text-lg leading-relaxed text-slate-600">${spec.intro.map(x=>`<p>${esc(x)}</p>`).join('')}</div>${cards(spec.cards)}</div></section><section class="bg-slate-50 py-16" id="diagnostics"><div class="mx-auto max-w-6xl px-4 sm:px-6 lg:px-8"><p class="text-sm font-extrabold uppercase tracking-[0.2em] text-brand-orange">Порядок проверки</p><h2 class="mt-3 text-3xl font-display font-extrabold text-brand-blue">Что фиксировать до разборки</h2><ol class="mt-8 grid gap-4 md:grid-cols-2 lg:grid-cols-4">${list(spec.steps)}</ol></div></section><section class="bg-white py-16" data-site-view-event="dishwasher_cause_matrix_viewed"><div class="mx-auto max-w-6xl px-4 sm:px-6 lg:px-8"><p class="text-sm font-extrabold uppercase tracking-[0.2em] text-brand-orange">Матрица диагностики</p><h2 class="mt-3 text-3xl font-display font-extrabold text-brand-blue">Какие контуры проверяются</h2>${matrix(spec.matrix)}</div></section>${related(page,slug)}${form(page,spec,slug)}<section class="border-t border-slate-200 bg-white py-12"><div class="mx-auto max-w-5xl px-4 sm:px-6 lg:px-8"><h2 class="text-2xl font-display font-extrabold text-brand-blue">Официальные материалы по оборудованию</h2><p class="mt-3 text-slate-600">Устройство, коды и процедуры применяются только в пределах указанных серий и моделей.</p><ul class="mt-6 grid gap-4 md:grid-cols-2">${evidenceList(entry.evidenceIds)}</ul></div></section></main>`;
}

for(const [page,spec] of Object.entries(pages)){
  const entry=manifestByPage.get(page); if(!entry) throw new Error(`Manifest missing ${page}`);
  const slug=slugOf(page);
  const header=headerTemplate.replaceAll('diagnostika-kuttera',slug);
  const footer=footerTemplate.replaceAll('diagnostika-kuttera',slug);
  const body=`<body class="font-sans text-slate-800 antialiased bg-white branch-restaurant page-dishwasher page-dishwasher-${esc(spec.kind)} page-${slug}" data-page-slug="${slug}" data-page-intent="${esc(entry.metrics.pageIntent)}" data-equipment="commercial_dishwasher" data-service="${esc(entry.metrics.service)}" data-commercial-segment="b2b_kitchen">${header}${main(page,entry,spec)}${faqSection(spec.faq)}${footer}</body></html>`;
  fs.writeFileSync(path.join(root,page), head(page,entry,spec)+body+'\n');
  entry.status='published'; entry.publicationWave=dw3Pages.has(page)?'DW3':'DW2';
  entry.title = entry.title.replace(/\s*\|\s*MosPochin$/,'');
  if(taxonomyByPage.has(page)){
    const t=taxonomyByPage.get(page); t.status='published'; t.publicationState='published';
  }
}

manifest.checkedAt='2026-07-14';
writeJson('data/dishwasher-cluster-pages.json',manifest);
writeJson('data/dishwasher-fault-taxonomy.json',taxonomy);

const graph=readJson('data/dishwasher-link-graph.json');
graph.mode='published-foundation-dw3';
for(const n of graph.nodes){
  if(pages[n.page]){
    n.status='published';
    n.actualOutgoing=commonLinks.filter(([p])=>p!==n.page).map(([p])=>p);
    n.plannedOutgoing=n.actualOutgoing;
  }
}
graph.checkedAt='2026-07-14';
writeJson('data/dishwasher-link-graph.json',graph);

const shots=readJson('data/dishwasher-screenshot-audit.json');
shots.status='active';
shots.artifactRoot='.artifacts/screenshots/dishwasher/native';
shots.browser='chromium';
shots.server={host:'127.0.0.1',port:9999};
shots.waitStrategy={networkIdleTimeoutMs:1500,postLoadDelayMs:2200};
shots.viewports=[
  {id:'desktop',label:'Desktop',width:1440,height:1080,deviceScaleFactor:1},
  {id:'mobile',label:'Mobile',width:393,height:852,deviceScaleFactor:2,isMobile:true,hasTouch:true}
];
shots.pages=Object.keys(pages).map(page=>({page,branch:'restaurant',pageType:'service',fullPage:true}));
shots.checkedAt='2026-07-14';
writeJson('data/dishwasher-screenshot-audit.json',shots);

const registry=readJson('data/cluster-registry.json');
registry.clusters.dishwasher.status='foundation';
writeJson('data/cluster-registry.json',registry);

const metadata=readJson('data/page-metadata.json');
for(const [page,spec] of Object.entries(pages)){
 const e=manifestByPage.get(page);
 metadata.pages[page]={title:`${e.title} | MosPochin`,description:spec.description,canonical:`https://mospochin.ru/${page}`,ogUrl:`https://mospochin.ru/${page}`,hasForm:true,branch:'restaurant'};
}
writeJson('data/page-metadata.json',metadata);

console.log(`Generated DW3 foundation: ${Object.keys(pages).length} published dishwasher pages.`);
